import { z } from 'zod';
import { Loader2 } from 'lucide-react';

const quizSchema = z.object({
  title: z.string(),
  questions: z.string(),
  duration: z.number(),
  passingScore: z.number(),
  maxAttempts: z.number(),
});

type QuizFormData = z.infer<typeof quizSchema>;

interface QuizFormProps {
  onSubmit: (data: QuizFormData) => Promise<void>;
  initialData?: Partial<QuizFormData>;
  isEdit?: boolean;
}

export default function QuizForm({ onSubmit, initialData, isEdit = false }: QuizFormProps) {
  const [isSubmitting, setIsSubmitting] = React.useState(false);

  const {
    register,
    handleSubmit,
    formState: { errors },
  } = useForm<QuizFormData>({
    resolver: zodResolver(quizSchema),
    defaultValues: initialData,
  });

  const handleFormSubmit = async (data: QuizFormData) => {
    setIsSubmitting(true);
    try {
      await onSubmit(data);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <form onSubmit={handleSubmit(handleFormSubmit)} className="space-y-4">

        <div>
          <label htmlFor="title" className="block text-sm font-medium text-gray-700 mb-1">
            Title
          </label>
          <input
            {...register('title')}
            type="text"
            id="title"
            className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
          />
          {errors.title && (
            <p className="mt-1 text-sm text-red-600">{errors.title.message}</p>
          )}
        </div>

        <div>
          <label htmlFor="duration" className="block text-sm font-medium text-gray-700 mb-1">
            Duration
          </label>
          <input
            {...register('duration', { valueAsNumber: true })}
            type="number"
            id="duration"
            className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
          />
        </div>

        <div>
          <label htmlFor="passingScore" className="block text-sm font-medium text-gray-700 mb-1">
            Passingscore
          </label>
          <input
            {...register('passingScore', { valueAsNumber: true })}
            type="number"
            id="passingScore"
            className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
          />
        </div>

        <div>
          <label htmlFor="maxAttempts" className="block text-sm font-medium text-gray-700 mb-1">
            Maxattempts
          </label>
          <input
            {...register('maxAttempts', { valueAsNumber: true })}
            type="number"
            id="maxAttempts"
            className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
          />
        </div>

      <button
        type="submit"
        disabled={isSubmitting}
        className="w-full py-2 px-4 bg-blue-600 text-white font-medium rounded-lg hover:bg-blue-700 focus:ring-2 focus:ring-blue-500 focus:ring-offset-2 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
      >
        {isSubmitting ? (
          <span className="flex items-center justify-center">
            <Loader2 className="w-5 h-5 mr-2 animate-spin" />
            {isEdit ? 'Updating...' : 'Creating...'}
          </span>
        ) : (
          isEdit ? 'Update Quiz' : 'Create Quiz'
        )}
      </button>
    </form>
  );
}
